# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration platform that manages users,
projects, tasks, messaging, performance dashboards, ratings and report
exports.  The public surface is the :class:`TeamCollaborationManager`,
which delegates to focused service objects.  All services share a single
re-entrant lock so that cross-entity operations stay consistent under
concurrent access.

Standard library only.
"""

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(enum.Enum):
    """Roles a user may hold within the platform."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(enum.Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Discriminator stored on every generated report."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the platform."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with the current state."""


# ---------------------------------------------------------------------------
# Data model
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _clone(obj):
    """Return an isolated deep copy so callers cannot mutate stored state."""

    return copy.deepcopy(obj)


def _require_text(value, field_name):
    """Validate that *value* is a non-empty string and return it trimmed."""

    if not isinstance(value, str) or not value.strip():
        raise ValidationError("{0} is required".format(field_name))
    return value.strip()


def _validate_email(value):
    """Validate a simple email address and return it trimmed."""

    if not isinstance(value, str):
        raise ValidationError("email is required")
    stripped = value.strip()
    if not stripped or "@" not in stripped:
        raise ValidationError("invalid email address")
    return stripped


def _pdf_escape(text):
    return text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")


def _build_pdf(title, lines):
    """Build a minimal but well-formed single-page PDF document."""

    text_lines = [title]
    text_lines.extend(lines)
    parts = ["BT", "/F1 12 Tf", "14 TL", "50 760 Td"]
    for index, raw in enumerate(text_lines):
        safe = _pdf_escape(str(raw))
        if index == 0:
            parts.append("({0}) Tj".format(safe))
        else:
            parts.append("T*")
            parts.append("({0}) Tj".format(safe))
    parts.append("ET")
    content = ("\n".join(parts)).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
        b"<< /Length " + str(len(content)).encode("ascii") + b" >>\nstream\n"
        + content + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for number, obj in enumerate(objects, start=1):
        offsets.append(len(out))
        out += "{0} 0 obj\n".format(number).encode("ascii") + obj + b"\nendobj\n"

    xref_pos = len(out)
    count = len(objects) + 1
    out += b"xref\n"
    out += "0 {0}\n".format(count).encode("ascii")
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += b"trailer\n<< /Size " + str(count).encode("ascii") + b" /Root 1 0 R >>\n"
    out += b"startxref\n" + str(xref_pos).encode("ascii") + b"\n%%EOF\n"
    return bytes(out)


def _report_to_lines(report):
    lines = []
    for key, value in report.items():
        if isinstance(value, dict):
            lines.append("{0}:".format(key))
            for sub_key, sub_value in value.items():
                lines.append("  {0}: {1}".format(sub_key, sub_value))
        elif isinstance(value, list):
            lines.append("{0}: {1} item(s)".format(key, len(value)))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


# ---------------------------------------------------------------------------
# Shared data store
# ---------------------------------------------------------------------------
class _DataStore:
    """Owns every in-memory collection plus the shared lock and id source."""

    def __init__(self, now):
        self.now = now
        self.lock = threading.RLock()
        self._id = 0

        self.users = {}
        self.projects = {}
        self.tasks = {}
        self.messages = {}
        self.ratings = {}

        self.username_index = {}
        self.email_index = {}
        self.tasks_by_project = {}
        self.tasks_by_assignee = {}
        self.messages_by_project = {}
        self.messages_by_task = {}
        self.ratings_by_ratee = {}

    def allocate_id(self):
        self._id += 1
        return self._id

    def current_time(self):
        return self.now()

    def require_user(self, user_id):
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id):
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id):
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id):
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message


class _BaseService:
    def __init__(self, store):
        self._store = store
        self._lock = store.lock


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class _UserService(_BaseService):
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            name = _require_text(username, "username")
            mail = _validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("invalid role")
            if name in self._store.username_index:
                raise DuplicateError("username already exists")
            if mail in self._store.email_index:
                raise DuplicateError("email already exists")
            user_id = self._store.allocate_id()
            user = User(
                id=user_id,
                username=name,
                email=mail,
                role=role,
                created_at=self._store.current_time(),
            )
            self._store.users[user_id] = user
            self._store.username_index[name] = user_id
            self._store.email_index[mail] = user_id
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            return _clone(self._store.require_user(user_id))

    def list_users(self):
        with self._lock:
            users = sorted(self._store.users.values(), key=lambda u: u.id)
            return [_clone(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._store.require_user(user_id)

            new_name = None
            if username is not None:
                new_name = _require_text(username, "username")
                owner = self._store.username_index.get(new_name)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already exists")

            new_mail = None
            if email is not None:
                new_mail = _validate_email(email)
                owner = self._store.email_index.get(new_mail)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("invalid role")

            if new_name is not None and new_name != user.username:
                self._store.username_index.pop(user.username, None)
                self._store.username_index[new_name] = user_id
                user.username = new_name
            if new_mail is not None and new_mail != user.email:
                self._store.email_index.pop(user.email, None)
                self._store.email_index[new_mail] = user_id
                user.email = new_mail
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self._store.require_user(user_id)
            for project in self._store.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task_id in self._store.tasks_by_assignee.get(user_id, set()):
                task = self._store.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")
            del self._store.users[user_id]
            self._store.username_index.pop(user.username, None)
            self._store.email_index.pop(user.email, None)


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class _ProjectService(_BaseService):
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            project_name = _require_text(name, "project name")
            if end_date < start_date:
                raise ValidationError("end date must not precede start date")
            self._store.require_user(owner_id)
            project_id = self._store.allocate_id()
            project = Project(
                id=project_id,
                name=project_name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._store.current_time(),
            )
            self._store.projects[project_id] = project
            self._store.tasks_by_project[project_id] = set()
            self._store.messages_by_project[project_id] = set()
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            return _clone(self._store.require_project(project_id))

    def list_projects(self):
        with self._lock:
            projects = sorted(self._store.projects.values(), key=lambda p: p.id)
            return [_clone(p) for p in projects]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self._store.require_project(project_id)
            new_name = project.name
            if name is not None:
                new_name = _require_text(name, "project name")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end date must not precede start date")
            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            task_ids = list(self._store.tasks_by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self._store.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    assigned = self._store.tasks_by_assignee.get(task.assignee_id)
                    if assigned is not None:
                        assigned.discard(task_id)
                for message_id in list(self._store.messages_by_task.get(task_id, set())):
                    self._store.messages.pop(message_id, None)
                self._store.messages_by_task.pop(task_id, None)
            self._store.tasks_by_project.pop(project_id, None)

            for message_id in list(self._store.messages_by_project.get(project_id, set())):
                self._store.messages.pop(message_id, None)
            self._store.messages_by_project.pop(project_id, None)

            del self._store.projects[project_id]


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class _TaskService(_BaseService):
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._store.require_project(project_id)
            task_title = _require_text(title, "task title")
            if assignee_id is not None:
                self._store.require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")
            task_id = self._store.allocate_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=task_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._store.current_time(),
            )
            self._store.tasks[task_id] = task
            self._store.tasks_by_project.setdefault(project_id, set()).add(task_id)
            if assignee_id is not None:
                self._store.tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            return _clone(self._store.require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            ids = self._store.tasks_by_project.get(project_id, set())
            tasks = sorted(
                (self._store.tasks[i] for i in ids if i in self._store.tasks),
                key=lambda t: t.id,
            )
            return [_clone(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._store.require_user(assignee_id)
            ids = self._store.tasks_by_assignee.get(assignee_id, set())
            tasks = sorted(
                (self._store.tasks[i] for i in ids if i in self._store.tasks),
                key=lambda t: t.id,
            )
            return [_clone(t) for t in tasks]

    def _set_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old is not None and old != new_assignee_id:
            assigned = self._store.tasks_by_assignee.get(old)
            if assigned is not None:
                assigned.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._store.tasks_by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def _assign(self, task_id, assignee_id):
        task = self._store.require_task(task_id)
        self._store.require_user(assignee_id)
        self._set_assignee(task, assignee_id)
        return _clone(task)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            return self._assign(task_id, assignee_id)

    def reassign_task(self, task_id, assignee_id):
        with self._lock:
            return self._assign(task_id, assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._store.require_task(task_id)
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._store.require_task(task_id)
            if deadline is not None:
                project = self._store.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._store.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("invalid task status")
            now = self._store.current_time()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class _MessageService(_BaseService):
    def _make_attachment(self, filename, data, uploaded_by, when):
        name = _require_text(filename, "attachment filename")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=name,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=when,
        )

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            self._store.require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._store.require_project(project_id)
            else:
                self._store.require_task(task_id)

            body_text = body if isinstance(body, str) else ""
            has_attachments = bool(attachments)
            if not body_text.strip() and not has_attachments:
                raise ValidationError("message requires a body or an attachment")

            if parent_id is not None:
                self._store.require_message(parent_id)

            when = self._store.current_time()
            attachment_objs = []
            if attachments:
                for item in attachments:
                    filename, data = item
                    attachment_objs.append(
                        self._make_attachment(filename, data, author_id, when)
                    )

            message_id = self._store.allocate_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=when,
                edited_at=None,
            )
            self._store.messages[message_id] = message
            if project_id is not None:
                self._store.messages_by_project.setdefault(project_id, set()).add(message_id)
            else:
                self._store.messages_by_task.setdefault(task_id, set()).add(message_id)
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit the message")
            body_text = new_body if isinstance(new_body, str) else ""
            if not body_text.strip() and not message.attachments:
                raise ValidationError("message requires a body or an attachment")
            message.body = body_text
            message.edited_at = self._store.current_time()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            attachment = self._make_attachment(
                filename, data, uploader_id, self._store.current_time()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            ids = self._store.messages_by_project.get(project_id, set())
            messages = sorted(
                (self._store.messages[i] for i in ids if i in self._store.messages),
                key=lambda m: m.id,
            )
            return [_clone(m) for m in messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._store.require_task(task_id)
            ids = self._store.messages_by_task.get(task_id, set())
            messages = sorted(
                (self._store.messages[i] for i in ids if i in self._store.messages),
                key=lambda m: m.id,
            )
            return [_clone(m) for m in messages]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete the message")
            self._store.messages.pop(message_id, None)
            if message.project_id is not None:
                bucket = self._store.messages_by_project.get(message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = self._store.messages_by_task.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class _PerformanceService(_BaseService):
    def _user_tasks(self, user_id):
        ids = self._store.tasks_by_assignee.get(user_id, set())
        return [self._store.tasks[i] for i in ids if i in self._store.tasks]

    @staticmethod
    def _durations(tasks):
        return [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]

    def _rating_stats(self, user_id):
        ids = self._store.ratings_by_ratee.get(user_id, set())
        scores = [self._store.ratings[i].score for i in ids if i in self._store.ratings]
        count = len(scores)
        average = sum(scores) / count if count else 0.0
        return count, average

    def get_completion_rate(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            durations = self._durations(self._user_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._store.require_user(rater_id)
            self._store.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int) \
                    or score < 1 or score > 5:
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None:
                self._store.require_task(task_id)
            rating_id = self._store.allocate_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._store.current_time(),
            )
            self._store.ratings[rating_id] = rating
            self._store.ratings_by_ratee.setdefault(ratee_id, set()).add(rating_id)
            return _clone(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            ids = self._store.ratings_by_ratee.get(user_id, set())
            ratings = sorted(
                (self._store.ratings[i] for i in ids if i in self._store.ratings),
                key=lambda r: r.id,
            )
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total else 0.0
            durations = self._durations(tasks)
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )
            rating_count, rating_average = self._rating_stats(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


