# Report service
# ---------------------------------------------------------------------------
class _ReportService(_BaseService):
    @staticmethod
    def _completion_metrics(tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        completion_rate = completed / total if total else 0.0
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        average = sum(durations) / len(durations) if durations else None
        return total, completed, completion_rate, average

    def _rating_stats(self, user_id):
        ids = self._store.ratings_by_ratee.get(user_id, set())
        scores = [self._store.ratings[i].score for i in ids if i in self._store.ratings]
        count = len(scores)
        average = sum(scores) / count if count else 0.0
        return count, average

    def project_progress_report(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            ids = self._store.tasks_by_project.get(project_id, set())
            tasks = [self._store.tasks[i] for i in ids if i in self._store.tasks]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0
            now = self._store.current_time()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.deadline < now
                and task.status != TaskStatus.COMPLETED
            )
            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "in_progress": 0, "not_started": 0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    bucket["in_progress"] += 1
                else:
                    bucket["not_started"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._store.require_project(project_id)
                ids = self._store.tasks_by_project.get(project_id, set())
                tasks = [self._store.tasks[i] for i in ids if i in self._store.tasks]
            else:
                tasks = list(self._store.tasks.values())

            by_assignee = {}
            for task in tasks:
                if task.assignee_id is not None:
                    by_assignee.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_assignee):
                user = self._store.users.get(user_id)
                total, completed, completion_rate, average = self._completion_metrics(
                    by_assignee[user_id]
                )
                rating_count, rating_average = self._rating_stats(user_id)
                rows.append({
                    "user_id": user_id,
                    "username": user.username if user is not None else "",
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": completion_rate,
                    "average_completion_time": average,
                    "rating_count": rating_count,
                    "rating_average": rating_average,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            user = self._store.require_user(user_id)
            ids = self._store.tasks_by_assignee.get(user_id, set())
            tasks = sorted(
                (self._store.tasks[i] for i in ids if i in self._store.tasks),
                key=lambda t: t.id,
            )
            total, completed, completion_rate, average = self._completion_metrics(tasks)
            rating_count, rating_average = self._rating_stats(user_id)
            task_rows = [
                {
                    "task_id": task.id,
                    "title": task.title,
                    "status": task.status.value,
                    "project_id": task.project_id,
                    "deadline": task.deadline,
                    "started_at": task.started_at,
                    "completed_at": task.completed_at,
                }
                for task in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completion_rate,
                "average_completion_time": average,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("invalid report format")
        if not isinstance(report, dict):
            raise ValidationError("invalid report payload")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _to_csv(report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in header])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow([
                "task_id", "title", "status", "project_id",
                "deadline", "started_at", "completed_at",
            ])
            for task in report.get("tasks", []):
                writer.writerow([
                    task.get("task_id", ""),
                    task.get("title", ""),
                    task.get("status", ""),
                    task.get("project_id", ""),
                    task.get("deadline", ""),
                    task.get("started_at", ""),
                    task.get("completed_at", ""),
                ])
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status:" + str(status), count])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, value])
        return output.getvalue()

    @staticmethod
    def _to_pdf(report):
        report_type = report.get("report_type", "report")
        title = "Report: {0}".format(report_type)
        return _build_pdf(title, _report_to_lines(report))


